old = load_snapshot()  # {name: {"hash": "...", "sig": {...}}}
new = {}
added, removed, updated = [], [], []
for job in jobs:
    sig_obj, h = job_signature(job)
    name = sig_obj["name"]
    new[name] = {"hash": h, "sig": sig_obj}
    if name not in old:
        added.append(sig_obj)
    else:
        if h != old[name]["hash"]:
            updated.append({"old": old[name]["sig"], "new": sig_obj})
for name in old:
    if name not in new:
        removed.append(old[name]["sig"])
if added or removed or updated:
    lines = [f"[{datetime.now().strftime('%Y-%m-%d %H:%M:%S')}] rjob 变化"]
    if added:
        lines.append("新增:")
        for j in added:
            lines.append(f"- {j['name']} (replicas={j['replicas']}, status={j['status']})")
    if removed:
        lines.append("删除:")
        for j in removed:
            lines.append(f"- {j['name']}")
    if updated:
        lines.append("更新:")
        for pair in updated:
            j = pair["new"]
            lines.append(f"- {j['name']} (replicas={j['replicas']}, status={j['status']})")
    print(f"[info] changes found: +{len(added)} / -{len(removed)} / ~{len(updated)}")
    feishu_text("\n".join(lines))
    save_snapshot(new)
else:
    print("[info] no changes, skip sending")
